// After: Clean, data-driven component
interface SidebarProps {
  config: SidebarSection[];
  expanded: Record<string, boolean>;
  onToggleSection: (id: string) => void;
}

export function Sidebar({ config, expanded, onToggleSection }: SidebarProps) {
  return (
    <nav className="sidebar">
      {config.map(section => (
        <div key={section.id}>
          <button onClick={() => onToggleSection(section.id)}>
            <Icon name={section.icon} />
            <span>{section.label}</span>
          </button>
          {expanded[section.id] && (
            <ul>
              {section.items.map(item => (
                <li key={item.href}>
                  <Link href={item.href}>
                    <Icon name={item.icon} />
                    <span>{item.label}</span>
                  </Link>
                </li>
              ))}
            </ul>
          )}
        </div>
      ))}
    </nav>
  );
}
